function SocialPoster() {
  const [text, setText] = React.useState('REPLACE_WITH_POST_TEXT');
  const [platform, setPlatform] = React.useState('twitter');
  const [scheduled, setScheduled] = React.useState([]);

  const limits = {twitter:280,facebook:2200,linkedin:3000};
  const len = text.length;
  const remaining = limits[platform] - len;

  const schedule = ()=>{
    if(!text.trim())return;
    setScheduled([{text,platform,time:new Date().toLocaleTimeString()},...scheduled]);
    setText('');
  };

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Social Poster</div>
      <div style={{display:'flex',gap:6,marginBottom:10}}>
        {Object.keys(limits).map(p=> (
          <button key={p} onClick={()=>setPlatform(p)}
            style={{padding:'6px 14px',borderRadius:8,border:'1px solid #ccc',background:platform===p?'#007AFF':'#fff',color:platform===p?'#fff':'#000',cursor:'pointer',fontSize:12,textTransform:'capitalize'}}>
            {p}
          </button>
        ))}
      </div>
      <textarea value={text} onChange={e=>setText(e.target.value)}
        style={{flex:1,padding:10,borderRadius:8,border:'1px solid #ccc',fontSize:14,resize:'none',marginBottom:8}}
        placeholder="What's on your mind?"/>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:10}}>
        <span style={{fontSize:12,color:remaining<0?'#FF3B30':remaining<20?'#FF9500':'#888'}}>
          {remaining} remaining
        </span>
        <button onClick={schedule}
          style={{padding:'8px 20px',borderRadius:8,background:'#34C759',color:'#fff',border:'none',cursor:'pointer',fontSize:14,fontWeight:600}}>
          Schedule Post
        </button>
      </div>
      <div style={{maxHeight:100,overflow:'auto'}}>
        {scheduled.map((s,i)=> (
          <div key={i} style={{padding:'6px 0',borderBottom:'1px solid #eee',fontSize:12}}>
            <span style={{textTransform:'capitalize',fontWeight:600,color:'#007AFF'}}>{s.platform}</span>
            <span style={{color:'#888',marginLeft:8}}>{s.time}</span>
            <div style={{color:'#555',marginTop:2}}>{s.text.slice(0,60)}…</div>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<SocialPoster/>);
